54: // BuildHTTPRoutes produces a list of routes for the proxy
55: func (configgen *ConfigGeneratorImpl) BuildHTTPRoutes(
56: 	node *model.Proxy,
57: 	req *model.PushRequest,
58: 	routeNames []string,
59: ) ([]*discovery.Resource, model.XdsLogDetails) {
60: 	var routeConfigurations model.Resources
61: 
62: 	efw := req.Push.EnvoyFilters(node)
63: 	hit, miss := 0, 0
64: 	switch node.Type {
65: 	case model.SidecarProxy, model.Waypoint:
66: 		vHostCache := make(map[int][]*route.VirtualHost)
67: 		// dependent envoyfilters' key, calculate in front once to prevent calc for each route.
68: 		envoyfilterKeys := efw.KeysApplyingTo(
69: 			networking.EnvoyFilter_ROUTE_CONFIGURATION,
70: 			networking.EnvoyFilter_VIRTUAL_HOST,
71: 			networking.EnvoyFilter_HTTP_ROUTE,
72: 		)
73: 		for _, routeName := range routeNames {
74: 			rc, cached := configgen.buildSidecarOutboundHTTPRouteConfig(node, req, routeName, vHostCache, efw, envoyfilterKeys)
75: 			if cached && !features.EnableUnsafeAssertions {
76: 				hit++
77: 			} else {
78: 				miss++
79: 			}
80: 			if rc == nil {
81: 				emptyRoute := &route.RouteConfiguration{
82: 					Name:             routeName,
83: 					VirtualHosts:     []*route.VirtualHost{},
84: 					ValidateClusters: proto.BoolFalse,
85: 				}
86: 				rc = &discovery.Resource{
87: 					Name:     routeName,
88: 					Resource: protoconv.MessageToAny(emptyRoute),
89: 				}
90: 			}
91: 			routeConfigurations = append(routeConfigurations, rc)
92: 		}
93: 	case model.Router:
94: 		for _, routeName := range routeNames {
95: 			rc := configgen.buildGatewayHTTPRouteConfig(node, req.Push, routeName)
96: 			if rc != nil {
97: 				rc = envoyfilter.ApplyRouteConfigurationPatches(networking.EnvoyFilter_GATEWAY, node, efw, rc)
98: 				resource := &discovery.Resource{
99: 					Name:     routeName,
100: 					Resource: protoconv.MessageToAny(rc),
101: 				}
102: 				routeConfigurations = append(routeConfigurations, resource)
103: 			}
104: 		}
105: 	}
106: 	if !features.EnableRDSCaching {
107: 		return routeConfigurations, model.DefaultXdsLogDetails
108: 	}
109: 	return routeConfigurations, model.XdsLogDetails{AdditionalInfo: fmt.Sprintf("cached:%v/%v", hit, hit+miss)}
110: }
